import java.lang.instrument.Instrumentation;
import java.lang.instrument.UnmodifiableClassException;

public class agentmain {
    public static void agentmain(String agentArgs, Instrumentation inst) throws UnmodifiableClassException {
        Class[] classes = inst.getAllLoadedClasses();
        // 判断类是否已经加载
        for (Class aClass : classes) {
            if (aClass.getName().equals(definetransform.editClassName)) {
                // 添加 Transformer
                inst.addTransformer(new definetransform(), true);
                // 触发 Transformer
                inst.retransformClasses(aClass);
            }
        }
    }
}


// definetransform.java
// 如果在使用过程中找不到javassist包中的类，那么可以使用URLCLassLoader+反射的方式调用
import javassist.ClassClassPath;
import javassist.ClassPool;
import javassist.CtClass;
import javassist.CtMethod;

import java.lang.instrument.ClassFileTransformer;
import java.lang.instrument.IllegalClassFormatException;
import java.security.ProtectionDomain;

public class definetransform implements ClassFileTransformer {
    public static final String editClassName = "hello";
    public static final String editMethod = "hello";

    @Override
    public byte[] transform(ClassLoader loader, String className, Class<?> classBeingRedefined, ProtectionDomain protectionDomain, byte[] classfileBuffer) throws IllegalClassFormatException {
        try{
            ClassPool cp = ClassPool.getDefault();
            if (classBeingRedefined != null) {
                ClassClassPath ccp = new ClassClassPath(classBeingRedefined);
                cp.insertClassPath(ccp);
                CtClass ctc = cp.get(editClassName);
                CtMethod method = ctc.getDeclaredMethod(editMethod);
                String source = "{System.out.println(\"hello transformer\");}";
                method.setBody(source);
                byte[] bytes = ctc.toBytecode();
                ctc.detach();
                return bytes;
            }

        } catch (Exception e) {
            e.printStackTrace();
        }
        return null;
    }
}

