// class Str{}

public static function studly(string $value): string
{
    $key = $value;
    if (isset(static::$studlyCache[$key])) {
        return static::$studlyCache[$key];
    }
    $value = ucwords(str_replace(['-', '_'], ' ', $value));
    return static::$studlyCache[$key] = str_replace(' ', '', $value);
